sys_script_client.script:
function onChange(control, oldValue, newValue, isLoading) {
    setActiveMessage(newValue);
}

function onLoad() {
    setActiveMessage(g_form.getValue('is_active'));
}

function setActiveMessage(val) {
    g_form.clearMessages();
    if (val === 'false' || val === '0' || val === false || val === 0 || val === '') {
        g_form.showFieldMsg('is_active',
            'This check is inactive and will not run during assessments. ' +
            'Click Activate Check in Related Links below to enable it.',
            'warning');
    } else {
        g_form.showFieldMsg('is_active',
            'This check is active and will run during assessments. ' +
            'Click Deactivate Check in Related Links below to disable it.',
            'info');
    }
}
